@* Vertical sidebar navigation for the settings page *@

<nav class="settings-sidebar">
    <h5 class="sidebar-title">Settings</h5>
    <ul class="nav flex-column">
        @foreach (var section in Sections)
        {
            <li class="nav-item">
                <button class="nav-link @(ActiveSection == section.Key ? "active" : "")"
                        @onclick="() => OnSectionChanged.InvokeAsync(section.Key)">
                    <span class="section-icon">@section.Value.Icon</span>
                    <span>@section.Value.Label</span>
                </button>
            </li>
        }
    </ul>
</nav>

@code {
    [Parameter] public string ActiveSection { get; set; } = "Profile";
    [Parameter] public EventCallback<string> OnSectionChanged { get; set; }

    private static readonly Dictionary<string, (string Label, string Icon)> Sections = new()
    {
        ["Profile"] = ("Profile", "👤"),
        ["Notifications"] = ("Notifications", "🔔"),
        ["Security"] = ("Security", "🔒"),
        ["Appearance"] = ("Appearance", "🎨"),
    };
}

@using sv_2697c4c2bc9c498b9691cfa90a1e1bf8.Services
@inject ISettingsService SettingsService

<div class="settings-section">
    <h3>Profile</h3>

    @if (_loading)
    {
        <p class="text-muted">Loading profile…</p>
    }
    else
    {
        <div class="profile-content">
            <div class="avatar-area mb-3">
                <img src="@_displayName" alt="Avatar" class="avatar-preview"
                     onerror="this.style.display='none'" style="display:none" />
                <div class="avatar-placeholder">
                    @(_displayName?.Length > 0 ? _displayName[0].ToString().ToUpper() : "?")
                </div>
                <div class="mt-2">
                    <label class="form-label fw-semibold">Avatar URL</label>
                    <input type="url" class="form-control" value="@_avatarUrl" disabled />
                </div>
            </div>

            <div class="mb-3">
                <label class="form-label fw-semibold">Display Name</label>
                <input type="text" class="form-control" @bind="_displayName" />
            </div>

            <div class="mb-3">
                <label class="form-label fw-semibold">Email</label>
                <input type="email" class="form-control" @bind="_email" />
            </div>

            <div class="mb-3">
                <label class="form-label fw-semibold">Bio</label>
                <textarea class="form-control" rows="3" @bind="_bio"></textarea>
            </div>

            <div class="d-flex gap-2">
                <button class="btn btn-primary" @onclick="SaveAsync" disabled="@_saving">
                    @(_saving ? "Saving…" : "Save Changes")
                </button>
                <button class="btn btn-outline-secondary" @onclick="Discard">
                    Discard Changes
                </button>
            </div>

            @if (_successMessage is not null)
            {
                <div class="alert alert-success mt-3 fade-in" role="alert">@_successMessage</div>
            }
        </div>
    }
</div>

@code {
    private string _displayName = "";
    private string _email = "";
    private string _avatarUrl = "";
    private string _bio = "";
    private UserProfile? _savedProfile;
    private bool _loading = true;
    private bool _saving;
    private string? _successMessage;

    protected override async Task OnInitializedAsync()
    {
        _savedProfile = await SettingsService.GetProfileAsync();
        ApplyProfile(_savedProfile);
        _loading = false;
    }

    private void ApplyProfile(UserProfile profile)
    {
        _displayName = profile.DisplayName;
        _email = profile.Email;
        _avatarUrl = profile.AvatarUrl;
        _bio = profile.Bio;
    }

    private async Task SaveAsync()
    {
        _saving = true;
        _successMessage = null;
        var updated = new UserProfile(_displayName, _email, _avatarUrl, _bio);
        await SettingsService.SaveProfileAsync(updated);
        _savedProfile = updated;
        _saving = false;
        _successMessage = "Profile saved successfully!";
        _ = ClearMessageAfterDelay();
    }

    private void Discard()
    {
        if (_savedProfile is not null)
            ApplyProfile(_savedProfile);
        _successMessage = null;
    }

    private async Task ClearMessageAfterDelay()
    {
        await Task.Delay(3000);
        _successMessage = null;
        await InvokeAsync(StateHasChanged);
    }
}

@using sv_2697c4c2bc9c498b9691cfa90a1e1bf8.Services
@inject ISettingsService SettingsService

<div class="settings-section">
    <h3>Notifications</h3>

    @if (_loading)
    {
        <p class="text-muted">Loading notification preferences…</p>
    }
    else
    {
        <div class="mb-4">
            <div class="form-check form-switch mb-2">
                <input class="form-check-input" type="checkbox" id="emailNotif"
                       checked="@_emailNotifications"
                       @onchange="e => _emailNotifications = (bool)(e.Value ?? false)" />
                <label class="form-check-label" for="emailNotif">Email Notifications</label>
            </div>
            <div class="form-check form-switch mb-2">
                <input class="form-check-input" type="checkbox" id="pushNotif"
                       checked="@_pushNotifications"
                       @onchange="e => _pushNotifications = (bool)(e.Value ?? false)" />
                <label class="form-check-label" for="pushNotif">Push Notifications</label>
            </div>
            <div class="form-check form-switch mb-2">
                <input class="form-check-input" type="checkbox" id="weeklyDigest"
                       checked="@_weeklyDigest"
                       @onchange="e => _weeklyDigest = (bool)(e.Value ?? false)" />
                <label class="form-check-label" for="weeklyDigest">Weekly Digest</label>
            </div>
        </div>

        <h5>Muted Channels</h5>
        <div class="muted-channels mb-4">
            @foreach (var channel in _channels)
            {
                <div class="form-check mb-1">
                    <input class="form-check-input" type="checkbox" id="@($"ch-{channel.Name}")"
                           checked="@channel.Muted"
                           @onchange="e => channel.Muted = (bool)(e.Value ?? false)" />
                    <label class="form-check-label" for="@($"ch-{channel.Name}")">
                        #@channel.Name
                    </label>
                </div>
            }
        </div>

        <button class="btn btn-primary" @onclick="SaveAsync" disabled="@_saving">
            @(_saving ? "Saving…" : "Save Preferences")
        </button>

        @if (_successMessage is not null)
        {
            <div class="alert alert-success mt-3 fade-in" role="alert">@_successMessage</div>
        }
    }
</div>

@code {
    private bool _emailNotifications;
    private bool _pushNotifications;
    private bool _weeklyDigest;
    private List<ChannelState> _channels = [];
    private bool _loading = true;
    private bool _saving;
    private string? _successMessage;

    protected override async Task OnInitializedAsync()
    {
        var prefs = await SettingsService.GetNotificationPrefsAsync();
        _emailNotifications = prefs.EmailNotifications;
        _pushNotifications = prefs.PushNotifications;
        _weeklyDigest = prefs.WeeklyDigest;
        _channels = prefs.MutedChannels
            .Select(c => new ChannelState { Name = c, Muted = true })
            .ToList();
        _loading = false;
    }

    private async Task SaveAsync()
    {
        _saving = true;
        _successMessage = null;
        var prefs = new NotificationPrefs(
            _emailNotifications,
            _pushNotifications,
            _weeklyDigest,
            _channels.Where(c => c.Muted).Select(c => c.Name).ToList());
        await SettingsService.SaveNotificationPrefsAsync(prefs);
        _saving = false;
        _successMessage = "Preferences saved!";
        _ = ClearMessageAfterDelay();
    }

    private async Task ClearMessageAfterDelay()
    {
        await Task.Delay(3000);
        _successMessage = null;
        await InvokeAsync(StateHasChanged);
    }

    private class ChannelState
    {
        public string Name { get; set; } = "";
        public bool Muted { get; set; }
    }
}

@using sv_2697c4c2bc9c498b9691cfa90a1e1bf8.Services

<h5>Active Sessions</h5>
<div class="table-responsive">
    <table class="table table-hover">
        <thead>
            <tr>
                <th>Device</th>
                <th>Location</th>
                <th>Last Active</th>
                <th></th>
            </tr>
        </thead>
        <tbody>
            @foreach (var session in Sessions)
            {
                <tr>
                    <td>@session.Device</td>
                    <td>@session.Location</td>
                    <td>@FormatLastActive(session.LastActive)</td>
                    <td>
                        @if (session.Id != CurrentSessionId)
                        {
                            @if (_confirmingId == session.Id)
                            {
                                <span class="me-2 text-danger fw-semibold">Revoke this session?</span>
                                <button class="btn btn-danger btn-sm me-1"
                                        @onclick="() => ConfirmRevoke(session.Id)">
                                    Yes
                                </button>
                                <button class="btn btn-outline-secondary btn-sm"
                                        @onclick="CancelRevoke">
                                    No
                                </button>
                            }
                            else
                            {
                                <button class="btn btn-outline-danger btn-sm"
                                        @onclick="() => RequestRevoke(session.Id)">
                                    Revoke
                                </button>
                            }
                        }
                        else
                        {
                            <span class="badge bg-success">Current</span>
                        }
                    </td>
                </tr>
            }
        </tbody>
    </table>
</div>

@code {
    [Parameter] public List<ActiveSession> Sessions { get; set; } = [];
    [Parameter] public string CurrentSessionId { get; set; } = "";
    [Parameter] public EventCallback<string> OnRevoke { get; set; }

    private string? _confirmingId;

    private void RequestRevoke(string sessionId) => _confirmingId = sessionId;
    private void CancelRevoke() => _confirmingId = null;

    private async Task ConfirmRevoke(string sessionId)
    {
        _confirmingId = null;
        await OnRevoke.InvokeAsync(sessionId);
    }

    private static string FormatLastActive(DateTime dt)
    {
        var diff = DateTime.UtcNow - dt;
        if (diff.TotalMinutes < 1) return "Just now";
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes}m ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
        return $"{(int)diff.TotalDays}d ago";
    }
}

@using sv_2697c4c2bc9c498b9691cfa90a1e1bf8.Services
@inject ISettingsService SettingsService

<div class="settings-section">
    <h3>Security</h3>

    @if (_loading)
    {
        <p class="text-muted">Loading security settings…</p>
    }
    else
    {
        <ChangePasswordPanel OnChangePassword="HandleChangePassword" />

        <div class="card mb-3">
            <div class="card-body d-flex justify-content-between align-items-center">
                <div>
                    <strong>Two-Factor Authentication</strong>
                    <div class="text-muted small">
                        @if (_twoFactorEnabled)
                        {
                            <span class="text-success">● Enabled</span>
                        }
                        else
                        {
                            <span class="text-warning">● Disabled</span>
                        }
                    </div>
                </div>
                <div class="form-check form-switch">
                    <input class="form-check-input" type="checkbox"
                           checked="@_twoFactorEnabled"
                           @onchange="e => _twoFactorEnabled = (bool)(e.Value ?? false)" />
                </div>
            </div>
        </div>

        @if (_lastPasswordChange.HasValue)
        {
            <p class="text-muted small mb-3">
                Last password change: @_lastPasswordChange.Value.ToString("MMM dd, yyyy")
            </p>
        }

        <ActiveSessionsTable Sessions="_sessions"
                             CurrentSessionId="@_currentSessionId"
                             OnRevoke="HandleRevoke" />
    }
</div>

@code {
    private bool _loading = true;
    private bool _twoFactorEnabled;
    private DateTime? _lastPasswordChange;
    private List<ActiveSession> _sessions = [];
    private string _currentSessionId = "sess-1"; // Simulate current session

    protected override async Task OnInitializedAsync()
    {
        var settings = await SettingsService.GetSecuritySettingsAsync();
        _twoFactorEnabled = settings.TwoFactorEnabled;
        _lastPasswordChange = settings.LastPasswordChange;
        _sessions = settings.Sessions.ToList();
        _loading = false;
    }

    private async Task HandleChangePassword((string Current, string New) args)
    {
        await SettingsService.ChangePasswordAsync(args.Current, args.New);
        _lastPasswordChange = DateTime.UtcNow;
    }

    private async Task HandleRevoke(string sessionId)
    {
        await SettingsService.RevokeSessionAsync(sessionId);
        _sessions.RemoveAll(s => s.Id == sessionId);
    }
}

@* Live preview of appearance settings *@

<div class="appearance-preview card @(_theme == "Dark" ? "bg-dark text-light" : "bg-light")"
     style="font-size: @FontSizeValue; @(_compactMode ? "padding: 0.5rem;" : "padding: 1.25rem;")">
    <div class="card-body">
        <h6 class="card-title">Preview</h6>
        <p class="card-text mb-2">
            This is how your content will look with the selected settings.
        </p>
        <div class="d-flex gap-2 align-items-center mb-2">
            <span class="badge @(_theme == "Dark" ? "bg-light text-dark" : "bg-primary")">Badge</span>
            <button class="btn btn-sm @(_theme == "Dark" ? "btn-outline-light" : "btn-outline-primary")">
                Sample Button
            </button>
        </div>
        <ul class="list-unstyled mb-0" style="@(_compactMode ? "line-height: 1.2;" : "")">
            <li>🌐 Language: @_language</li>
            <li>🎨 Theme: @_theme</li>
            <li>📏 Font: @_fontSize</li>
            <li>📐 Compact: @(_compactMode ? "On" : "Off")</li>
        </ul>
    </div>
</div>

@code {
    [Parameter] public string Theme { get => _theme; set => _theme = value; }
    [Parameter] public string FontSize { get => _fontSize; set => _fontSize = value; }
    [Parameter] public string Language { get => _language; set => _language = value; }
