{"file_text": "<div class="card mb-3">
    <div class="card-header d-flex justify-content-between align-items-center"
         style="cursor: pointer" @onclick="Toggle">
        <strong>Change Password</strong>
        <span>@(_expanded ? "▲" : "▼")</span>
    </div>

    @if (_expanded)
    {
        <div class="card-body">
            <div class="mb-3">
                <label class="form-label">Current Password</label>
                <input type="password" class="form-control" @bind="_currentPassword" />
            </div>
            <div class="mb-3">
                <label class="form-label">New Password</label>
                <input type="password" class="form-control" @bind="_newPassword" />
            </div>
            <div class="mb-3">
                <label class="form-label">Confirm New Password</label>
                <input type="password" class="form-control" @bind="_confirmPassword" />
            </div>

            @if (_errorMessage is not null)
            {
                <div class="alert alert-danger" role="alert">@_errorMessage</div>
            }
            @if (_successMessage is not null)
            {
                <div class="alert alert-success fade-in" role="alert">@_successMessage</div>
            }

            <button class="btn btn-warning" @onclick="UpdatePasswordAsync" disabled="@_saving">
                @(_saving ? "Updating…" : "Update Password")
            </button>
        </div>
    }
</div>

@code {
    [Parameter] public EventCallback<(string Current, string New)> OnChangePassword { get; set; }

    private bool _expanded;
    private string _currentPassword = "";
    private string _newPassword = "";
    private string _confirmPassword = "";
    private string? _errorMessage;
    private string? _successMessage;
    private bool _saving;

    private void Toggle() => _expanded = !_expanded;

    private async Task UpdatePasswordAsync()
    {
        _errorMessage = null;
        _successMessage = null;

        if (string.IsNullOrWhiteSpace(_currentPassword))
        {
            _errorMessage = "Current password is required.";
            return;
        }
        if (_newPassword.Length < 6)
        {
            _errorMessage = "New password must be at least 6 characters.";
            return;
        }
        if (_newPassword != _confirmPassword)
        {
            _errorMessage = "Passwords do not match.";
            return;
        }

        _saving = true;
        await OnChangePassword.InvokeAsync((_currentPassword, _newPassword));
        _saving = false;
        _successMessage = "Password updated successfully!";
        _currentPassword = "";
        _newPassword = "";
        _confirmPassword = "";
    }
}
", "path": "/tmp/sv-2697c4c2bc9c498b9691cfa90a1e1bf8/Components/Pages/Settings/ChangePasswordPanel.razor"}

{"file_text": "@using sv_2697c4c2bc9c498b9691cfa90a1e1bf8.Services

<h5>Active Sessions</h5>
<div class="table-responsive">
    <table class="table table-hover">
        <thead>
            <tr>
                <th>Device</th>
                <th>Location</th>
                <th>Last Active</th>
                <th></th>
            </tr>
        </thead>
        <tbody>
            @foreach (var session in Sessions)
            {
                <tr>
                    <td>@session.Device</td>
                    <td>@session.Location</td>
                    <td>@FormatLastActive(session.LastActive)</td>
                    <td>
                        @if (session.Id != CurrentSessionId)
                        {
                            @if (_confirmingId == session.Id)
                            {
                                <span class="me-2 text-danger fw-semibold">Revoke this session?</span>
                                <button class="btn btn-danger btn-sm me-1"
                                        @onclick="() => ConfirmRevoke(session.Id)">
                                    Yes
                                </button>
                                <button class="btn btn-outline-secondary btn-sm"
                                        @onclick="CancelRevoke">
                                    No
                                </button>
                            }
                            else
                            {
                                <button class="btn btn-outline-danger btn-sm"
                                        @onclick="() => RequestRevoke(session.Id)">
                                    Revoke
                                </button>
                            }
                        }
                        else
                        {
                            <span class="badge bg-success">Current</span>
                        }
                    </td>
                </tr>
            }
        </tbody>
    </table>
</div>

@code {
    [Parameter] public List<ActiveSession> Sessions { get; set; } = [];
    [Parameter] public string CurrentSessionId { get; set; } = "";
    [Parameter] public EventCallback<string> OnRevoke { get; set; }

    private string? _confirmingId;

    private void RequestRevoke(string sessionId) => _confirmingId = sessionId;
    private void CancelRevoke() => _confirmingId = null;

    private async Task ConfirmRevoke(string sessionId)
    {
        _confirmingId = null;
        await OnRevoke.InvokeAsync(sessionId);
    }

    private static string FormatLastActive(DateTime dt)
    {
        var diff = DateTime.UtcNow - dt;
        if (diff.TotalMinutes < 1) return "Just now";
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes}m ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
        return $"{(int)diff.TotalDays}d ago";
    }
}
