@using sv_2697c4c2bc9c498b9691cfa90a1e1bf8.Services

<h5>Active Sessions</h5>
<div class="table-responsive">
    <table class="table table-hover">
        <thead>
            <tr>
                <th>Device</th>
                <th>Location</th>
                <th>Last Active</th>
                <th></th>
            </tr>
        </thead>
        <tbody>
            @foreach (var session in Sessions)
            {
                <tr>
                    <td>@session.Device</td>
                    <td>@session.Location</td>
                    <td>@FormatLastActive(session.LastActive)</td>
                    <td>
                        @if (session.Id != CurrentSessionId)
                        {
                            @if (_confirmingId == session.Id)
                            {
                                <span class="me-2 text-danger fw-semibold">Revoke this session?</span>
                                <button class="btn btn-danger btn-sm me-1"
                                        @onclick="() => ConfirmRevoke(session.Id)">
                                    Yes
                                </button>
                                <button class="btn btn-outline-secondary btn-sm"
                                        @onclick="CancelRevoke">
                                    No
                                </button>
                            }
                            else
                            {
                                <button class="btn btn-outline-danger btn-sm"
                                        @onclick="() => RequestRevoke(session.Id)">
                                    Revoke
                                </button>
                            }
                        }
                        else
                        {
                            <span class="badge bg-success">Current</span>
                        }
                    </td>
                </tr>
            }
        </tbody>
    </table>
</div>

@code {
    [Parameter] public List<ActiveSession> Sessions { get; set; } = [];
    [Parameter] public string CurrentSessionId { get; set; } = "";
    [Parameter] public EventCallback<string> OnRevoke { get; set; }

    private string? _confirmingId;

    private void RequestRevoke(string sessionId) => _confirmingId = sessionId;
    private void CancelRevoke() => _confirmingId = null;

    private async Task ConfirmRevoke(string sessionId)
    {
        _confirmingId = null;
        await OnRevoke.InvokeAsync(sessionId);
    }

    private static string FormatLastActive(DateTime dt)
    {
        var diff = DateTime.UtcNow - dt;
        if (diff.TotalMinutes < 1) return "Just now";
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes}m ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
        return $"{(int)diff.TotalDays}d ago";
    }
}

