toolArgs.file_text:
@* Live preview of appearance settings *@

<div class="appearance-preview card @(_theme == "Dark" ? "bg-dark text-light" : "bg-light")"
     style="font-size: @FontSizeValue; @(_compactMode ? "padding: 0.5rem;" : "padding: 1.25rem;")">
    <div class="card-body">
        <h6 class="card-title">Preview</h6>
        <p class="card-text mb-2">
            This is how your content will look with the selected settings.
        </p>
        <div class="d-flex gap-2 align-items-center mb-2">
            <span class="badge @(_theme == "Dark" ? "bg-light text-dark" : "bg-primary")">Badge</span>
            <button class="btn btn-sm @(_theme == "Dark" ? "btn-outline-light" : "btn-outline-primary")">
                Sample Button
            </button>
        </div>
        <ul class="list-unstyled mb-0" style="@(_compactMode ? "line-height: 1.2;" : "")">
            <li>🌐 Language: @_language</li>
            <li>🎨 Theme: @_theme</li>
            <li>📏 Font: @_fontSize</li>
            <li>📐 Compact: @(_compactMode ? "On" : "Off")</li>
        </ul>
    </div>
</div>

@code {
    [Parameter] public string Theme { get => _theme; set => _theme = value; }
    [Parameter] public string FontSize { get => _fontSize; set => _fontSize = value; }
    [Parameter] public string Language { get => _language; set => _language = value; }
    [Parameter] public bool CompactMode { get => _compactMode; set => _compactMode = value; }

    private string _theme = "Light";
    private string _fontSize = "Medium";
    private string _language = "English";
    private bool _compactMode;

    private string FontSizeValue => _fontSize switch
    {
        "Small" => "0.85rem",
        "Large" => "1.15rem",
        _ => "1rem"
    };
}

@using sv_2697c4c2bc9c498b9691cfa90a1e1bf8.Services
@inject ISettingsService SettingsService

<div class="settings-section">
    <h3>Appearance</h3>

    @if (_loading)
    {
        <p class="text-muted">Loading appearance settings…</p>
    }
    else
    {
        <div class="row">
            <div class="col-md-6">
                <div class="mb-4">
                    <label class="form-label fw-semibold">Theme</label>
                    <div>
                        @foreach (var theme in new[] { "Light", "Dark", "System" })
                        {
                            <div class="form-check">
                                <input class="form-check-input" type="radio" name="theme"
                                       id="@($"theme-{theme}")" value="@theme"
                                       checked="@(_theme == theme)"
                                       @onchange="() => _theme = theme" />
                                <label class="form-check-label" for="@($"theme-{theme}")">@theme</label>
                            </div>
                        }
                    </div>
                </div>

                <div class="mb-4">
                    <label class="form-label fw-semibold">Font Size</label>
                    <div>
                        @foreach (var size in new[] { "Small", "Medium", "Large" })
                        {
                            <div class="form-check">
                                <input class="form-check-input" type="radio" name="fontSize"
                                       id="@($"fs-{size}")" value="@size"
                                       checked="@(_fontSize == size)"
                                       @onchange="() => _fontSize = size" />
                                <label class="form-check-label" for="@($"fs-{size}")">@size</label>
                            </div>
                        }
                    </div>
                </div>

                <div class="mb-4">
                    <label class="form-label fw-semibold" for="language-select">Language</label>
                    <select id="language-select" class="form-select" @bind="_language">
                        @foreach (var lang in _languages)
                        {
                            <option value="@lang">@lang</option>
                        }
                    </select>
                </div>

                <div class="form-check form-switch mb-4">
                    <input class="form-check-input" type="checkbox" id="compactMode"
                           checked="@_compactMode"
                           @onchange="e => _compactMode = (bool)(e.Value ?? false)" />
                    <label class="form-check-label" for="compactMode">Compact Mode</label>
                </div>

                <button class="btn btn-primary" @onclick="SaveAsync" disabled="@_saving">
                    @(_saving ? "Saving…" : "Save")
                </button>

                @if (_successMessage is not null)
                {
                    <div class="alert alert-success mt-3 fade-in" role="alert">@_successMessage</div>
                }
            </div>

            <div class="col-md-6">
                <AppearancePreview Theme="@_theme"
                                   FontSize="@_fontSize"
                                   Language="@_language"
                                   CompactMode="@_compactMode" />
            </div>
        </div>
    }
</div>

@code {
    private string _theme = "Light";
    private string _fontSize = "Medium";
    private string _language = "English";
    private bool _compactMode;
    private bool _loading = true;
    private bool _saving;
    private string? _successMessage;

    private static readonly string[] _languages =
        ["English", "Spanish", "French", "German", "Japanese", "Chinese", "Portuguese"];

    protected override async Task OnInitializedAsync()
    {
        var settings = await SettingsService.GetAppearanceAsync();
        _theme = settings.Theme;
        _fontSize = settings.FontSize;
        _language = settings.Language;
        _compactMode = settings.CompactMode;
        _loading = false;
    }

    private async Task SaveAsync()
    {
        _saving = true;
        _successMessage = null;
        await SettingsService.SaveAppearanceAsync(
            new AppearanceSettings(_theme, _fontSize, _language, _compactMode));
        _saving = false;
        _successMessage = "Appearance saved!";
        _ = ClearMessageAfterDelay();
    }

    private async Task ClearMessageAfterDelay()
    {
        await Task.Delay(3000);
        _successMessage = null;
        await InvokeAsync(StateHasChanged);
    }
}

