arguments.file_text:
@page "/settings"
@rendermode InteractiveServer

<PageTitle>Settings</PageTitle>

<div class="settings-dashboard">
    <SettingsSidebar ActiveSection="@_activeSection"
                     OnSectionChanged="section => _activeSection = section" />

    <div class="settings-content">
        @switch (_activeSection)
        {
            case "Profile":
                <ProfileSection />
                break;
            case "Notifications":
                <NotificationsSection />
                break;
            case "Security":
                <SecuritySection />
                break;
            case "Appearance":
                <AppearanceSection />
                break;
        }
    </div>
</div>

@code {
    private string _activeSection = "Profile";
}

/* ── Settings Dashboard Layout ── */

.settings-dashboard {
    display: flex;
    min-height: calc(100vh - 4rem);
    gap: 0;
}

/* ── Sidebar ── */

::deep .settings-sidebar {
    width: 220px;
    min-width: 220px;
    background: #f8f9fa;
    border-right: 1px solid #dee2e6;
    padding: 1.5rem 0;
}

::deep .sidebar-title {
    padding: 0 1.25rem 0.75rem;
    margin: 0;
    font-size: 0.85rem;
    text-transform: uppercase;
    letter-spacing: 0.05em;
    color: #6c757d;
}

::deep .settings-sidebar .nav-link {
    display: flex;
    align-items: center;
    gap: 0.6rem;
    padding: 0.6rem 1.25rem;
    color: #495057;
    border: none;
    background: none;
    width: 100%;
    text-align: left;
    font-size: 0.95rem;
    cursor: pointer;
    border-left: 3px solid transparent;
    transition: background 0.15s, border-color 0.15s;
}

::deep .settings-sidebar .nav-link:hover {
    background: #e9ecef;
}

::deep .settings-sidebar .nav-link.active {
    background: #e7f1ff;
    color: #0d6efd;
    font-weight: 600;
    border-left-color: #0d6efd;
}

::deep .section-icon {
    font-size: 1.1rem;
}

/* ── Content Area ── */

.settings-content {
    flex: 1;
    padding: 2rem;
    max-width: 900px;
}

::deep .settings-section h3 {
    margin-bottom: 1.5rem;
    padding-bottom: 0.5rem;
    border-bottom: 1px solid #dee2e6;
}

/* ── Profile avatar ── */

::deep .avatar-preview {
    width: 80px;
    height: 80px;
    border-radius: 50%;
    object-fit: cover;
    border: 2px solid #dee2e6;
}

::deep .avatar-placeholder {
    width: 80px;
    height: 80px;
    border-radius: 50%;
    background: #0d6efd;
    color: white;
    display: flex;
    align-items: center;
    justify-content: center;
    font-size: 2rem;
    font-weight: 600;
}

/* ── Toast / success message fade ── */

::deep .fade-in {
    animation: fadeInOut 3s ease-in-out;
}

@keyframes fadeInOut {
    0%   { opacity: 0; }
    10%  { opacity: 1; }
    80%  { opacity: 1; }
    100% { opacity: 0; }
}

/* ── Appearance preview card ── */

::deep .appearance-preview {
    border: 1px solid #dee2e6;
    border-radius: 0.5rem;
    transition: all 0.2s ease;
}

